const manifest = require('./manifest.json');
const schema = require('./schema.json');

// Check release field
if (manifest.release !== 'v2.4.0') {
  console.log('✗ Release field not preserved correctly');
  process.exit(1);
}
if (!/^v[0-9]+\.[0-9]+\.[0-9]+$/.test(manifest.release)) {
  console.log('✗ Release format invalid');
  process.exit(1);
}
console.log('✓ release field valid: ' + manifest.release);

// Check components is an array
if (!Array.isArray(manifest.components)) {
  console.log('✗ components is not an array');
  process.exit(1);
}
console.log('✓ components is an array');

// Check exactly 3 items
if (manifest.components.length !== 3) {
  console.log('✗ components has ' + manifest.components.length + ' items, expected 3');
  process.exit(1);
}
console.log('✓ components has exactly 3 items');

// Check components are unique
const names = manifest.components.map(c => c.name);
if (new Set(names).size !== names.length) {
  console.log('✗ components are not unique');
  process.exit(1);
}
console.log('✓ components are unique');

// Check order
if (names[0] !== 'catalog' || names[1] !== 'fetcher' || names[2] !== 'leaderboard') {
  console.log('✗ components not in correct order');
  process.exit(1);
}
console.log('✓ components in correct order: catalog, fetcher, leaderboard');

// Check each component has only name and version
for (const comp of manifest.components) {
  const keys = Object.keys(comp);
  if (keys.length !== 2) {
    console.log('✗ Component has extra fields: ' + JSON.stringify(comp));
    process.exit(1);
  }
  if (!keys.includes('name') || !keys.includes('version')) {
    console.log('✗ Component missing required fields: ' + JSON.stringify(comp));
    process.exit(1);
  }
}
console.log('✓ Each component has only name and version');

// Check version format (semver without 'v')
const versionPattern = /^[0-9]+\.[0-9]+\.[0-9]+$/;
for (const comp of manifest.components) {
  if (!versionPattern.test(comp.version)) {
    console.log('✗ Invalid version format: ' + comp.version);
    process.exit(1);
  }
}
console.log('✓ All versions in correct semver format');

console.log('');
console.log('=== All validation checks passed ===');
"

node -e "
const manifest = require('./manifest.json');

// Verify JSON is valid
console.log('✓ JSON is valid');

// Check for any potential privacy-sensitive keys
const privacyKeywords = ['password', 'secret', 'key', 'token', 'auth', 'credential', 'private', 'email', 'phone', 'address', 'ssn', 'credit', 'card'];
const found = [];
function checkObj(obj, path) {
  for (const [k, v] of Object.entries(obj)) {
    const lowerK = k.toLowerCase();
    for (const kw of privacyKeywords) {
      if (lowerK.includes(kw) && !['token'].includes(lowerK) && lowerK !== 'version') { 
        // version is ok, but 'token' in a key would be flagged
        if (lowerK.includes('token')) found.push(path + '.' + k);
      }
    }
    if (typeof v === 'object' && v !== null) checkObj(v, path + '.' + k);
  }
}
checkObj(manifest, 'root');

if (found.length > 0) {
  console.log('⚠ Privacy scan found:', found);
} else {
  console.log('✓ Privacy scan: zero hits');
}
"
